-- W1.6 questions batch 2675/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-6f0ba476-moex-00471', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列關於婚姻效力之敘述，何者正確？', '["夫妻於家庭生活所產生之費用，除另有約定外，由夫妻各依其經濟 能力、家事勞動或其他情事分擔之", "夫妻各保有其本姓，但得書面約定冠配偶之姓，並向法院公證處登 記後公告之，以兼顧社會交易安全與個人隱私", "夫妻雖互負同居義務，但一方於婚後財產不當減損，或難以維持共 同生活時，他方及其未成年子女得請求分居，並向戶政機關登記之， 始生分居之法律效力", "婚後之夫妻共同住所，應載明於書面協議，並至戶政機關登記後， 請求法院公證之，始生夫妻同居之效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00472', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲、乙結婚後，乙生下丙。依民法規定，下列關於婚生子女推定之 敘述，何者正確？', '["乙之生產，係在與甲婚姻關係存續中，故推定丙為乙之婚生子女", "乙之生產，係在與甲婚姻關係存續中，故推定丙為甲之婚生子女", "如推定丙為甲之婚生子女，甲得依法證明丙非其血緣而提起婚生否 認之訴，否認丙為甲之婚生子女", "如推定丙為甲之婚生子女，生父丁得證明丙為丁之血緣而提起婚生 否認之訴，否認丙為甲之婚生子女"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00473', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '關於遺產之繼承與繼承權之喪失，下列敘述，何者正確？', '["繼承人對於被繼承人侮辱並經被繼承人表示其不得繼承，其後再經 被繼承人宥恕者，其繼承權不喪失。然被繼承人之宥恕，應以書面 表示，並由全體繼承人共同見證且簽名，始生繼承權未喪失之效力", "未成年人、已受監護宣告或輔助宣告之人，如受被繼承人生前持續 扶養者，應由全體繼承人依其維持生活必要程度，按月酌給遺產", "繼承人故意致被繼承人或應繼承人於死或雖未致死因而受刑之宣 告者，喪失其繼承權", "胎兒之生母為繼承人，且對被繼承人妨害其撤回或變更遺囑者，該 生母與胎兒均喪失繼承權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00474', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列關於遺囑方式之敘述，何者錯誤？', '["遺囑應依法定方式為之，否則不生效力", "自書遺囑者，應自書遺囑全文，記明年、月、日，並親自簽名", "自書遺囑，如有增減、塗改，應註明增減、塗改之處所及字數，另 行簽名", "自書遺囑應指定兩人以上之見證人同行簽名"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00475', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲生前分別因其子女乙、丙、丁之結婚，各贈送時價新臺幣（下同） 300 萬元、200 萬元、100 萬元之戒指 A、B、C。5 年後甲死亡時，甲 留下300萬元存款；戒指A、B，價值已分別下跌為200萬元、130萬元 ，戒指C則已滅失。甲之繼承人乙、丙、丁分割遺產時，應如何處理？', '["乙無須返還，亦不受分配", "丙扣除受贈價額後，得再分配 80 萬元", "丙得受分配270 萬元", "丁得受分配100 萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00476', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'essay', '在所得稅制中，資本利得（capitalgains）往往於實現時才納入課稅，
並給予優惠措施。何謂資本利得？依據「所得」的定義，資本利得是
否應該納入課稅？又資本利得於實現時課稅，是否應給予優惠措施？
請依據學理試述己見。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "6f34d20004a3", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1006", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00477', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'essay', '社會大眾所稱之「奢侈稅」，即特種貨物及勞務稅，於民國100年6月
開徵。請以其租稅客體為完全競爭市場之財貨為例，分別說明達成下
列兩個目的的主要影響因素及其效果。需求者（高所得者）負擔較
高稅負；抑止「奢侈品」消費。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "6f34d20004a3", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1006", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00478', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '下列何種租稅是直轄市及縣（市）稅？', '["遺產及贈與稅", "菸酒稅", "貨物稅", "土地增值稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "6f34d20004a3", "answer_pdf_sha1": "db3ff28e6084", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00479', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '一個好的稅制所應具備的特性，不包含下列那一項？', '["公平性（Fairness）", "適應性（Flexibility）", "即時性（Immediateness）", "政治責任性（Politicalresponsibility）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "6f34d20004a3", "answer_pdf_sha1": "db3ff28e6084", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00480', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '在一完全競爭市場中對財貨課徵貨物稅，假設法定納稅義務人為供給者， 且該財貨的需求彈性為零，貨物稅的租稅歸宿為何？', '["供給者與需求者各負擔一半", "供給者完全負擔", "需求者完全負擔", "供給者負擔三分之二，需求者負擔剩餘的三分之一"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "6f34d20004a3", "answer_pdf_sha1": "db3ff28e6084", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
